/* ── Color mappings ──
 * Each entry carries THREE colour slots because the badge text and the
 * distribution-bar fill have different WCAG requirements:
 *   bg   → the soft badge background (-soft token)
 *   text → the badge FOREGROUND (Badge/TokenBadge `color:`) — must pass AA as
 *          text, so warning/error use the darker `-text` variant.
 *   fill → the SimpleBar chart FILL (applied as `background:` via colorFn) —
 *          a graphical element (3:1), so it keeps the saturated token for
 *          vivid chart bars. (success has no `-text` variant and passes AA, so
 *          its text and fill are the same token.) */
const TIER_COLORS = {
  'Tier 1': { bg: 'var(--da-color-success-soft)', text: 'var(--da-color-success)', fill: 'var(--da-color-success)' },
  'Tier 2': { bg: 'var(--da-color-warning-soft)', text: 'var(--da-color-warning-text)', fill: 'var(--da-color-warning)' },
  'Tier 3': { bg: 'var(--da-color-error-soft)', text: 'var(--da-color-error-text)', fill: 'var(--da-color-error)' },
};

const GROUP_COLORS = {
  A: { bg: 'var(--da-color-success-soft)', text: 'var(--da-color-success)', fill: 'var(--da-color-success)', label: 'Mature' },
  B: { bg: 'var(--da-color-warning-soft)', text: 'var(--da-color-warning-text)', fill: 'var(--da-color-warning)', label: 'Partial' },
  C: { bg: 'var(--da-color-error-soft)', text: 'var(--da-color-error-text)', fill: 'var(--da-color-error)', label: 'Unmigrated' },
};

/* ── Sub-components ── */
// Converged to the shared _common MetricCard (Phase B2). `accent` maps to the
// shared card's value-tone slot, preserving this tool's semantic health colour
// (success / info / error on the value).
function KpiCard({ value, label, accent }) {
  return <MetricCardBase value={value} label={label} accent={accent} />;
}

function Badge({ tier }) {
  const tierKey = tier.startsWith('Tier 3') ? 'Tier 3' : tier;
  const colors = TIER_COLORS[tierKey] || TIER_COLORS['Tier 2'];
  return (
    <span style={{ ...styles.badge, background: colors.bg, color: colors.text }}>
      {tier}
    </span>
  );
}

function TokenBadge({ group }) {
  const c = GROUP_COLORS[group] || GROUP_COLORS.C;
  return (
    <span style={{ ...styles.badge, background: c.bg, color: c.text }} title={c.label}>
      {group} — {c.label}
    </span>
  );
}

function ProgressCell({ ratio }) {
  const pct = Math.round(ratio * 100);
  // Split the fill color from the label color: the bar fill is a background
  // (saturated is correct), but the % label is text on a light td — so it must
  // use the AA -text variant. success has no -text variant and already passes AA.
  const barColor = pct >= 95 ? 'var(--da-color-success)' : pct >= 80 ? 'var(--da-color-warning)' : 'var(--da-color-error)';
  const labelColor = pct >= 95 ? 'var(--da-color-success)' : pct >= 80 ? 'var(--da-color-warning-text)' : 'var(--da-color-error-text)';
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--da-space-2)' }}>
      <div style={styles.progressBar} role="progressbar" aria-valuenow={pct} aria-valuemin={0} aria-valuemax={100} aria-label={`i18n coverage ${pct}%`}>
        <div style={{ ...styles.progressFill, width: `${pct}%`, background: barColor }} />
      </div>
      <span style={{ fontSize: 'var(--da-font-size-xs)', minWidth: '36px' /* token-exempt: fixed label width */, color: labelColor }}>{pct}%</span>
    </div>
  );
}

function SimpleBar({ items, maxVal, colorFn }) {
  return (
    <div style={styles.barChart} role="img" aria-label={t('分佈圖', 'Distribution chart')}>
      {items.map(({ label, value }) => {
        const h = maxVal > 0 ? Math.max(4, (value / maxVal) * 100) : 4;
        return (
          <div key={label} style={styles.barGroup}>
            <div style={styles.barValue}>{value}</div>
            <div style={{ width: '100%', maxWidth: '60px' /* token-exempt: bar width cap */, height: `${h}px`, borderRadius: 'var(--da-radius-sm)', background: colorFn(label), transition: 'height 0.3s ease' }} />
            <div style={styles.barLabel}>{label}</div>
          </div>
        );
      })}
    </div>
  );
}

/* ── Main Component ── */
export default function ComponentHealth() {
  const [tierFilter, setTierFilter] = useState('all');
  const [sortCol, setSortCol] = useState('tierScore');
  const [sortAsc, setSortAsc] = useState(false);

  const allTiers = ['all', 'Tier 1', 'Tier 2', 'Tier 3'];

  const filtered = useMemo(() => {
    let data = HEALTH_DATA;
    if (tierFilter !== 'all') {
      data = data.filter(d => d.tier.startsWith(tierFilter));
    }
    return [...data].sort((a, b) => {
      let va = a[sortCol], vb = b[sortCol];
      if (typeof va === 'boolean') { va = va ? 1 : 0; vb = vb ? 1 : 0; }
      if (typeof va === 'string') return sortAsc ? va.localeCompare(vb) : vb.localeCompare(va);
      return sortAsc ? va - vb : vb - va;
    });
  }, [tierFilter, sortCol, sortAsc]);

  /* ── Aggregate stats ── */
  const stats = useMemo(() => {
    const total = HEALTH_DATA.length;
    const tier1 = HEALTH_DATA.filter(d => d.tier === 'Tier 1').length;
    const groupA = HEALTH_DATA.filter(d => d.group === 'A').length;
    const groupB = HEALTH_DATA.filter(d => d.group === 'B').length;
    const groupC = HEALTH_DATA.filter(d => d.group === 'C').length;
    const pwCov = HEALTH_DATA.filter(d => d.pw).length;
    const avgI18n = HEALTH_DATA.reduce((s, d) => s + d.i18n, 0) / total;
    const tier1Pw = HEALTH_DATA.filter(d => d.tier === 'Tier 1' && d.pw).length;
    const tier1Total = tier1;
    return { total, tier1, groupA, groupB, groupC, pwCov, avgI18n, tier1Pw, tier1Total };
  }, []);

  const handleSort = (col) => {
    if (sortCol === col) setSortAsc(!sortAsc);
    else { setSortCol(col); setSortAsc(false); }
  };

  const sortIcon = (col) => sortCol === col ? (sortAsc ? ' ↑' : ' ↓') : '';

  /* ── Distribution data ── */
  const tierDist = [
    { label: 'Tier 1', value: stats.tier1 },
    { label: 'Tier 2', value: HEALTH_DATA.filter(d => d.tier.startsWith('Tier 2')).length },
    { label: 'Tier 3', value: HEALTH_DATA.filter(d => d.tier.startsWith('Tier 3')).length },
  ];
  const tokenDist = [
    { label: 'A', value: stats.groupA },
    { label: 'B', value: stats.groupB },
    { label: 'C', value: stats.groupC },
  ];

  return (
    <div style={styles.container}>
      {/* Header */}
      <header style={styles.header}>
        <h1 style={styles.title}>{t('元件健康儀表板', 'Component Health Dashboard')}</h1>
        <p style={styles.subtitle}>{t(
          'v2.7.0 Phase .a 基準線 — 38 個互動工具的品質、覆蓋率與設計 Token 合規概覽',
          'v2.7.0 Phase .a baseline — quality, coverage & design token compliance for 38 interactive tools'
        )}</p>
      </header>

      {/* KPI Row */}
      <div style={styles.kpiRow} role="region" aria-label={t('關鍵指標', 'Key metrics')}>
        <KpiCard value={stats.total} label={t('總工具數', 'Total Tools')} />
        <KpiCard value={`${stats.tier1Pw}/${stats.tier1Total}`} label={t('Tier 1 Playwright', 'Tier 1 Playwright')} accent="var(--da-color-success)" />
        <KpiCard value={`${stats.pwCov}/${stats.total}`} label={t('Playwright 覆蓋', 'Playwright Coverage')} />
        <KpiCard value={`${Math.round(stats.avgI18n * 100)}%`} label={t('平均 i18n 覆蓋', 'Avg i18n Coverage')} accent="var(--da-color-info)" />
        <KpiCard value={`${stats.groupA}`} label={t('Token Group A', 'Token Group A')} accent="var(--da-color-success)" />
        <KpiCard value={`${stats.groupC}`} label={t('Token Group C', 'Token Group C')} accent="var(--da-color-error-text)" />
      </div>

      {/* Distribution Charts */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--da-space-4)' }}>
        <div style={styles.section}>
          <h2 style={styles.sectionTitle}>{t('Tier 分佈', 'Tier Distribution')}</h2>
          <SimpleBar
            items={tierDist}
            maxVal={Math.max(...tierDist.map(d => d.value))}
            colorFn={(label) => TIER_COLORS[label]?.fill || 'var(--da-color-muted)'}
          />
        </div>
        <div style={styles.section}>
          <h2 style={styles.sectionTitle}>{t('Design Token 合規', 'Design Token Compliance')}</h2>
          <SimpleBar
            items={tokenDist}
            maxVal={Math.max(...tokenDist.map(d => d.value))}
            colorFn={(label) => GROUP_COLORS[label]?.fill || 'var(--da-color-muted)'}
          />
        </div>
      </div>

      {/* Tool Table */}
      <div style={styles.section}>
        <h2 style={{ ...styles.sectionTitle, marginBottom: 'var(--da-space-4)' }}>
          {t('工具明細', 'Tool Details')}
        </h2>

        {/* Tier filter */}
        <div style={styles.filterRow} role="radiogroup" aria-label={t('Tier 篩選', 'Tier filter')}>
          {allTiers.map(tier => (
            <button
              key={tier}
              role="radio"
              aria-checked={tierFilter === tier}
              onClick={() => setTierFilter(tier)}
              style={{
                ...styles.filterBtn,
                ...(tierFilter === tier ? styles.filterBtnActive : {}),
              }}
            >
              {tier === 'all' ? t('全部', 'All') : tier}
            </button>
          ))}
        </div>

        <div style={{ overflowX: 'auto' }}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th} onClick={() => handleSort('title')}>
                  {t('工具', 'Tool')}{sortIcon('title')}
                </th>
                <th style={styles.th} onClick={() => handleSort('tierScore')}>
                  {t('Tier', 'Tier')}{sortIcon('tierScore')}
                </th>
                <th style={styles.th} onClick={() => handleSort('group')}>
                  {t('Token', 'Token')}{sortIcon('group')}
                </th>
                <th style={styles.th} onClick={() => handleSort('tokens')}>
                  {t('Tokens', 'Tokens')}{sortIcon('tokens')}
                </th>
                <th style={styles.th} onClick={() => handleSort('palette')}>
                  {t('Palette', 'Palette')}{sortIcon('palette')}
                </th>
                <th style={styles.th} onClick={() => handleSort('i18n')}>
                  {t('i18n', 'i18n')}{sortIcon('i18n')}
                </th>
                <th style={styles.th} onClick={() => handleSort('pw')}>
                  {t('Playwright', 'PW')}{sortIcon('pw')}
                </th>
                <th style={styles.th} onClick={() => handleSort('loc')}>
                  {t('LOC', 'LOC')}{sortIcon('loc')}
                </th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(tool => (
                <tr key={tool.key}>
                  <td style={styles.td}>
                    <strong>{tool.title}</strong>
                    <div style={{ fontSize: 'var(--da-font-size-xs)', color: 'var(--da-color-muted)' }}>{tool.key}</div>
                  </td>
                  <td style={styles.td}><Badge tier={tool.tier} /></td>
                  <td style={styles.td}><TokenBadge group={tool.group} /></td>
                  <td style={styles.td}>{tool.tokens}</td>
                  <td style={styles.td}>
                    <span style={{ color: tool.palette > 0 ? 'var(--da-color-error-text)' : 'var(--da-color-success)' }}>
                      {tool.palette}
                    </span>
                  </td>
                  <td style={{ ...styles.td, minWidth: '120px' /* token-exempt: table column min width */ }}>
                    <ProgressCell ratio={tool.i18n} />
                  </td>
                  <td style={styles.td}>
                    <span
                      role="img"
                      aria-label={tool.pw ? t('有 Playwright 測試', 'Has Playwright test') : t('無 Playwright 測試', 'No Playwright test')}
                    >
                      {tool.pw ? <span aria-hidden="true">✓</span> : '—'}
                    </span>
                  </td>
                  <td style={styles.td}>{tool.loc}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={{ marginTop: 'var(--da-space-4)', fontSize: 'var(--da-font-size-xs)', color: 'var(--da-color-muted)' }}>
          {t(
            `顯示 ${filtered.length} / ${HEALTH_DATA.length} 工具 · 資料來源：scan_component_health.py · 快照日期：2026-04-17`,
            `Showing ${filtered.length} / ${HEALTH_DATA.length} tools · Source: scan_component_health.py · Snapshot: 2026-04-17`
          )}
        </div>
      </div>

      {/* Legend */}
      <div style={{ ...styles.section, fontSize: 'var(--da-font-size-sm)', color: 'var(--da-color-muted)' }}>
        <h2 style={{ ...styles.sectionTitle, fontSize: 'var(--da-font-size-base)' }}>{t('圖例', 'Legend')}</h2>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--da-space-4)' }}>
          <div>
            <strong>{t('Tier 評分 (DEC-08)', 'Tier Scoring (DEC-08)')}</strong>
            <p style={{ margin: 'var(--da-space-1) 0' }}>{t(
              '5 維度加權：LOC + Audience + Journey Phase + Writer + Recency。Tier 1 ≥7, Tier 2 4-6, Tier 3 ≤3。',
              '5-dimensional weighted: LOC + Audience + Journey Phase + Writer + Recency. Tier 1 ≥7, Tier 2 4-6, Tier 3 ≤3.'
            )}</p>
          </div>
          <div>
            <strong>{t('Token Group', 'Token Group')}</strong>
            <p style={{ margin: 'var(--da-space-1) 0' }}>{t(
              'A = density ≥10/100LOC, 0 palette · B = 部分遷移 · C = 未遷移（density <5, ≥5 palette）',
              'A = density ≥10/100LOC, 0 palette · B = partial migration · C = unmigrated (density <5, ≥5 palette)'
            )}</p>
          </div>
        </div>
      </div>
    </div>
  );
}
